const cfg = $input.first().json;
const source_url = (cfg.source_url || '').toString().trim();
let page_content = '';
if (source_url) {
  try {
    const res = await this.helpers.httpRequest({ url: source_url, method: 'GET', headers: { 'User-Agent': 'Mozilla/5.0 (compatible; n8n)' }, timeout: 15000 });
    const raw = typeof res === 'string' ? res : JSON.stringify(res);
    page_content = raw
      .replace(/<script[\s\S]*?<\/script>/gi, ' ')
      .replace(/<style[\s\S]*?<\/style>/gi, ' ')
      .replace(/<[^>]+>/g, ' ')
      .replace(/&nbsp;/gi, ' ')
      .replace(/\s+/g, ' ')
      .trim()
      .slice(0, 4000);
  } catch (e) {
    page_content = '';
  }
}
return [{ json: Object.assign({}, cfg, { source_url, page_content }) }];

